class Detector(nn.Module):
    """
    This in an interface for neural network learning to predict boxes.
    The trainer expects "compute_loss" and "get_boxes" to be coded.
    """

    def __init__(self):
        super(Detector, self).__init__()

    def get_boxes(self, x, score_thresh=0.4):
        raise NotImplementedError()

    def compute_loss(self, x, targets):
        raise NotImplementedError()


class SingleStageDetector(Detector):
    """ This in an interface for "single stage" methods (e.g: RetinaNet, SSD, etc.)

    Args:
        feature_extractor (string): name of the feature extractor architecture
        in_channels (int): number of channels for the input layer
        num_classes (int): number of output classes for the classifier head
        feature_base(int): factor to grow the feature extractor width
        feature_channels_out(int): number of output channels for the feature extractor
        anchor_list (couple list): list of couple (aspect ratio, scale) to be used for each extracted feature
        max_boxes_per_input (int): max number of boxes to be considered before thresholding or NMS.
    """

    def __init__(self, feature_extractor,# Vanilla
                 in_channels,# 10
                 num_classes,# 7
                 feature_base,# 16
                 feature_channels_out,# 256
                 anchor_list,# PSEE_ANCHORS
                 nlayers=0, max_boxes_per_input=500): #max_boxes_per_input在hparams里的默认值就是500
        #这里的nlayers其实是BoxHead里的box_head和cls_head的中间层conv叠加多少次，默认不叠加
        super(SingleStageDetector, self).__init__()
        feature_extractor = getattr(feat, feature_extractor) #是feature_extractors.py里的 Vanilla 网骆

        self.num_classes = num_classes # 7
        self.in_channels = in_channels # 10

        self.feature_extractor = feature_extractor(in_channels, base=feature_base, cout=feature_channels_out) #实例化好的Vanilla网骆
        # self.feature_extractor = feature_extractor(2*in_channels, base=feature_base, cout=feature_channels_out) #实例化好的Vanilla网骆 通道数翻倍以适应过累积读取
        self.box_coder = Anchors(num_levels=self.feature_extractor.levels, # 5, 来自Vanilla网骆的默认属性，可以主动更改，比如4
                                 anchor_list=anchor_list,
                                 variances=[0.1, 0.2])

        self.num_anchors = self.box_coder.num_anchors #默认的 PSEE_ANCHORS 是 6 个anchors
        self.max_boxes_per_input = max_boxes_per_input #500

        self.rpn = rpn_module.BoxHead(self.feature_extractor.cout, self.box_coder.num_anchors,
                                      self.num_classes + 1, nlayers) #SSD_head

        self.criterion = DetectionLoss("softmax_focal_loss")

        #============================自己添加的=================================
        # self.FE0=FE(feature_channels_out)#默认分8组
        # self.FE1=FE(feature_channels_out)
        # self.FE2=FE(feature_channels_out)
        # self.FE3=FE(feature_channels_out)
        # self.AFPN=AFPN(in_channels=[feature_channels_out, feature_channels_out, feature_channels_out, feature_channels_out], out_channels=feature_channels_out)
        # self.GFPN=GhostFPN(feature_channels_out, feature_channels_out)
        # self.GFPN=GhostFPNLite(feature_channels_out, feature_channels_out)
        #============================自己添加的=================================

    def forward(self, x):
        xs = self.feature_extractor(x)
        return self.rpn(xs)

    def select_valid_frames(self, xs, targets, frame_is_labeled):
        frame_is_labeled = frame_is_labeled.bool()
        mask = frame_is_labeled.view(-1)
        xs = [item[mask] for item in xs]
        targets = [
            [targets[r][c] for c in range(len(frame_is_labeled[0])) if frame_is_labeled[r][c]]
            for r in range(len(frame_is_labeled))]
        return xs, targets

    def compute_loss(self, x, targets, frame_is_labeled):
        # x : [num_tbin, batch_size, c, h, w] 为了简洁表示，用 t 指代 num_tbin ,用 n 指代 batch_size, tn其实就是t*n
        # targets: 二维列表(num_tbin*batch_size),每个element都是[*,6]形状的array(dtype=float32) 第二维的 '6' 依次代表x1,y1,x2,y2,class_id,track_id
        # frame_is_labeled: [num_tbin, batch_size] 代表某个delta_t的ev_repr是否含有至少一个gt框

        xs = self.feature_extractor(x) #xs,列表,包含5个level的特征: [tn,cout,h/8,w/8] [tn,cout,h/16,w/16] [tn,cout,h/32,w/32] [tn,cout,h/64,w/64] [tn,cout,h/128,w/128]

        #============================自己添加的=================================
        # xs[0]=self.FE0(xs[0])
        # xs[1]=self.FE1(xs[1])
        # xs[2]=self.FE2(xs[2])
        # xs[3]=self.FE3(xs[3])
        # xs = self.AFPN(xs) # xs = [x0, x1, x2, x3]
        # xs = self.GFPN(xs)
        #============================自己添加的=================================

        if frame_is_labeled.sum().item() == 0:
            return None

        xs, targets = self.select_valid_frames(xs, targets, frame_is_labeled)
        # xs,列表,仍然包含5个level的特征，但是已经经过了筛选，只保留了有label的部分，即第一维度统一由tn变成了n'(有效的delta_t的数量)
        # targets, 二维列表, 但是也只保留了有效位置的label(根据frame_is_labeled)

        loc_preds, cls_preds = self.rpn(xs)
        # loc_preds 的形状为[n',total_num_priors,4],包含预测框的位置信息 n' 即后面的 N 
        # cls_preds 的形状为[n',total_num_priors,8],包含预测框的类别信息
        # total_num_priors 指的是5个阶段的prior总数(cat到一起的)，每个阶段的prior数量等于那个阶段的h*w*num_anchors 也可用 A (accumulated) 来简介表示

        targets = list(chain.from_iterable(targets)) #把有效的label数组按照展平顺序(一行一行 从上到下)依次放进一个列表 共有n'个
        targets = self.box_coder.encode(xs, x, targets) #{"loc": loc_targets, "cls": cls_targets}
        # loc_targets [N,A,4](delta_x, delta_y, scale_W, scale_h) 整体的逻辑就是 destination ÷ source . 得到每个prior应有的偏移量,已经经过了encode.
        # cls_targets [N,A] 每个prior对应的id

        assert targets['cls'].shape[1] == cls_preds.shape[1]

        loss_dict = self.criterion(loc_preds, targets['loc'], cls_preds, targets["cls"])
        return loss_dict

    def get_boxes(self, x, score_thresh=0.4, nms_thresh=0.6):
        features = self.feature_extractor(x)
        #============================自己添加的=================================
        # features[0]=self.FE0(features[0])
        # features[1]=self.FE1(features[1])
        # features[2]=self.FE2(features[2])
        # features[3]=self.FE3(features[3])
        # features = self.AFPN(features) # xs = [x0, x1, x2, x3]
        # features = self.GFPN(features)
        #============================自己添加的=================================
        #注意，相较于train过程，inference过程没有tn->n'的过程，即N指的就是tn
        loc_preds, cls_preds = self.rpn(features)
        scores = self.rpn.get_scores(cls_preds) #先在最后一维softmax，然后除去第0类的背景，得到[N,A,7] 
        return self.box_coder.decode(features, x, loc_preds, scores, batch_size=x.shape[1], score_thresh=score_thresh,
                                     nms_thresh=nms_thresh, max_boxes_per_input=self.max_boxes_per_input) #只有在inference的时候才会进行NMS, (self.box_coder.decode->batched_decode->batched_nms)

    def reset(self, mask=torch.zeros((1,), dtype=torch.float32)):
        for name, module in self._modules.items():
            if hasattr(module, "reset"):
                module.reset(mask)

    def reset_all(self):
        for name, module in self._modules.items():
            if hasattr(module, "reset_all"):
                module.reset_all()

    def freeze_feature_extractor(self, is_frozen):
        for param in self.feature_extractor.parameters():
            param.requires_grad = not is_frozen

    def map_cls_weights(self, module_src, old_classes, new_classes):
        """
        Maps old classes to new classes
        if some overlap exists between old classes and new ones.

        Args:
            module_src: old model
            old_classes: old list of classes
            new_classes: new list of classes
        """
        self.rpn.init_cls_head()
        old_classes = ['background'] + old_classes
        new_classes = ['background'] + new_classes
        old_map = {label: i for i, label in enumerate(old_classes)}
        src_weight, src_bias = module_src.rpn.get_classification_params()
        dst_weight, dst_bias = self.rpn.get_classification_params()
        for dst_idx, dst_label in enumerate(new_classes):
            if dst_label in old_map:
                print(dst_label, 'was in old set: transfer weights...')
                src_idx = old_map[dst_label]
                dst_weight.data[:, dst_idx] = src_weight[:, src_idx]
                dst_bias.data[:, dst_idx] = src_bias[:, src_idx]
